package com.palhelper.app.data

import com.palhelper.app.data.model.structure.MaterialCost
import com.palhelper.app.data.model.structure.Structure
import com.palhelper.app.data.model.structure.StructureCategory

/**
 * Dataset completo das construções de base do Palworld 1.0 (429 estruturas).
 *
 * Os custos vêm de um arquivo de dados 1.0 verificado, fornecido pelo usuário — cada quantidade
 * de material corresponde ao jogo. Nomes exibidos em português. Ícones (estruturas e materiais)
 * carregados ao vivo do palworld.gg; estruturas sem token de ícone conhecido usam um ícone
 * genérico da categoria. `techLevel` nulo = disponível desde o início.
 *
 * Para manter o arquivo enxuto, os materiais ficam numa tabela ([materials]) e cada estrutura
 * referencia-os por id via [c]; os prefixos de URL do palworld.gg são montados em [itemIcon]/
 * [structIcon]. Assim os ~960 custos não repetem URLs longas.
 */
object StructureDataSource {

    private const val ITEM_BASE = "https://palworld.gg/images/items/"

    private fun itemIcon(token: String) = ITEM_BASE + token + ".png"
    private fun structIcon(token: String) = ITEM_BASE + token + ".png"

