    /** Build a [MaterialCost] from a material id + amount, resolving name/icon from [materials]. */
    private fun c(id: String, amount: Int): MaterialCost {
        val m = materials.getValue(id)
        return MaterialCost(id, m.displayName, amount, iconUrl = itemIcon(m.iconToken))
    }

