    private val F = StructureCategory.FOUNDATION
    private val P = StructureCategory.PRODUCT
    private val S_ = StructureCategory.STORAGE
    private val A = StructureCategory.PALS
    private val I = StructureCategory.INFRASTRUCTURE
    private val O = StructureCategory.FOOD          // cOmida
    private val D = StructureCategory.DEFENSE
    private val L = StructureCategory.LIGHT
    private val T = StructureCategory.OTHER         // ouTros

    /** Row helper: id, PT name, category, techLevel, structure icon token, costs. */
    private fun S(
        id: String, name: String, category: StructureCategory, tech: Int?,
        icon: String, vararg costs: MaterialCost
    ) = Structure(id, name, category, tech, costs.toList(), iconUrl = structIcon(icon))

